export const CONTENT: Record<string, InterestContent> = {
  economics:        economics,
  neuroscience:     neuroscience,
  'climate change': climateChange,
  climate:          climateChange,
  fashion:          fashion,
  robotics:         robotics,
}

export function resolveInterest(input: string): InterestContent | null {
  const normalized = input.toLowerCase().trim()
  if (CONTENT[normalized]) return CONTENT[normalized]
  return (
    Object.values(CONTENT).find(
      c =>
        c.id.includes(normalized) ||
        normalized.includes(c.id) ||
        c.label.toLowerCase().includes(normalized)
    ) ?? null
  )
}
